import java.util.Arrays;
import java.util.Comparator;
import java.util.List;

public class Solution {
    public int[] smallest_difference_room(int[][] rooms, int[][] queries) {
        int n = rooms.length;
        int k = queries.length;
        int[] results = new int[k];
        Arrays.sort(rooms, Comparator.comparingInt(a -> a[0]));

        for (int i = 0; i < k; i++) {
            int preferred = queries[i][0];
            int minSize = queries[i][1];
            int diff = Integer.MAX_VALUE;
            int room_idx = -1;

            for (int j = 0; j < n; j++) {
                if (rooms[j][1] >= minSize) {
                    int tmp_diff = Math.abs(preferred - rooms[j][0]);
                    if (tmp_diff < diff) {
                        diff = tmp_diff;
                        room_idx = rooms[j][0];
                    }
                }
            }
            results[i] = room_idx;
        }
        return results;
    }
}
```

